<?php
namespace app\Requests; class Validator{ public static function required(array $data,array $fields):array{ $e=[]; foreach($fields as $f=>$label){ if(!isset($data[$f])||trim((string)$data[$f])==='') $e[$f]="$label không được để trống"; } return $e; } public static function email(array $data,string $field,string $label):array{ return (!empty($data[$field])&&!filter_var($data[$field],FILTER_VALIDATE_EMAIL))?[$field=>"$label không đúng định dạng"]:[]; } public static function numberMin(array $data,string $field,string $label,int|float $min):array{ return (isset($data[$field])&&$data[$field]!==''&&(float)$data[$field]<$min)?[$field=>"$label phải lớn hơn hoặc bằng $min"]:[]; }}
